\displaystyle{\begin{aligned}
   \frac{5}{6} + \frac{9}{10}
        \amp = \frac{25}{30} + \frac{27}{30} \\
        \amp = \frac{25 + 27}{30} \\
        \amp = \frac{52}{30} \amp \hbox{We can reduce this by dividing 2 into both the numerator and the denominator.
}\\
        \amp = \frac{26}{15}
\end{aligned}
    }
